import React, { useState, useEffect } from 'react';
import { getDSAProblems, markProblemSolved, markUnsolved } from '../services/api';

function DSATracker() {
  const [problems, setProblems]       = useState([]);
  const [solved, setSolved]           = useState({});
  const [loading, setLoading]         = useState(true);
  const [filter, setFilter]           = useState({ sheet: 'All', difficulty: 'All' });
  const [activeGroup, setActiveGroup] = useState(null);

  useEffect(() => { fetchProblems(); }, []);

  const fetchProblems = async () => {
    try {
      const res = await getDSAProblems();
      setProblems(res.data.problems);
      const savedSolved = JSON.parse(localStorage.getItem('devnest_solved') || '{}');
      setSolved(savedSolved);
    } catch (err) {
      console.error('Failed to fetch problems', err);
    } finally {
      setLoading(false);
    }
  };

  const toggleSolved = async (problem) => {
    const isSolved = solved[problem._id];
    try {
      if (isSolved) { await markUnsolved(problem._id); }
      else { await markProblemSolved(problem._id); }
      const updated = { ...solved, [problem._id]: !isSolved };
      setSolved(updated);
      localStorage.setItem('devnest_solved', JSON.stringify(updated));
    } catch (err) {
      console.error('Failed to toggle', err);
    }
  };

  const filtered = problems.filter(p => {
    if (filter.sheet !== 'All' && p.sheet !== filter.sheet) return false;
    if (filter.difficulty !== 'All' && p.difficulty !== filter.difficulty) return false;
    return true;
  });

  const grouped = filtered.reduce((acc, p) => {
    if (!acc[p.topic]) acc[p.topic] = [];
    acc[p.topic].push(p);
    return acc;
  }, {});

  const totalSolved   = Object.values(solved).filter(Boolean).length;
  const totalProblems = problems.length;
  const percentage    = totalProblems ? Math.round((totalSolved / totalProblems) * 100) : 0;

  const dc = { Easy: '#22c55e', Medium: '#f59e0b', Hard: '#ef4444' };

  if (loading) return (
    <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'60vh', gap:'12px' }}>
      <div style={{ fontSize:'40px' }}>📊</div>
      <div style={{ color:'#22c55e', fontSize:'14px' }}>Loading problems...</div>
    </div>
  );

  return (
    <div style={{ padding:'0', fontFamily:"'Segoe UI', sans-serif", color:'#ffffff' }}>

      {/* Header */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:'20px' }}>
        <div>
          <h1 style={{ fontSize:'22px', fontWeight:'600', color:'#ffffff', marginBottom:'4px' }}>DSA Tracker</h1>
          <p style={{ fontSize:'12px', color:'#4b5563' }}>Track your progress across sheets</p>
        </div>
        <div style={{ background:'#0f0f0f', border:'1px solid #1a1a1a', borderRadius:'14px', padding:'16px 20px', minWidth:'220px' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'10px' }}>
            <span style={{ fontSize:'12px', color:'#6b7280' }}>Overall Progress</span>
            <span style={{ fontSize:'20px', fontWeight:'700', color:'#22c55e' }}>{percentage}%</span>
          </div>
          <div style={{ height:'4px', background:'#1a1a1a', borderRadius:'999px', overflow:'hidden', marginBottom:'8px' }}>
            <div style={{ height:'100%', width:`${percentage}%`, background:'#22c55e', borderRadius:'999px', transition:'width 0.5s ease' }}></div>
          </div>
          <div style={{ fontSize:'11px', color:'#4b5563' }}>{totalSolved} of {totalProblems} solved</div>
        </div>
      </div>

      {/* Stats */}
      <div style={{ display:'flex', gap:'10px', marginBottom:'20px', flexWrap:'wrap' }}>
        {[
          { label:'Total',  value: totalProblems, color:'#ffffff' },
          { label:'Solved', value: totalSolved,   color:'#22c55e' },
          { label:'Easy',   value: problems.filter(p => p.difficulty==='Easy').length,   color:'#22c55e' },
          { label:'Medium', value: problems.filter(p => p.difficulty==='Medium').length, color:'#f59e0b' },
          { label:'Hard',   value: problems.filter(p => p.difficulty==='Hard').length,   color:'#ef4444' },
        ].map(stat => (
          <div key={stat.label} style={{ background:'#0f0f0f', border:'1px solid #1a1a1a', borderRadius:'10px', padding:'10px 16px', display:'flex', flexDirection:'column', alignItems:'center', gap:'2px', minWidth:'70px' }}>
            <span style={{ fontSize:'20px', fontWeight:'700', color: stat.color }}>{stat.value}</span>
            <span style={{ fontSize:'10px', color:'#6b7280' }}>{stat.label}</span>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display:'flex', alignItems:'center', gap:'20px', marginBottom:'20px', flexWrap:'wrap', background:'#0f0f0f', border:'1px solid #1a1a1a', borderRadius:'12px', padding:'12px 16px' }}>
        <div style={{ display:'flex', alignItems:'center', gap:'6px' }}>
          <span style={{ fontSize:'11px', color:'#6b7280', marginRight:'4px' }}>Sheet:</span>
          {['All','Blind75','Striver'].map(sheet => (
            <button key={sheet}
              style={{ padding:'5px 12px', background: filter.sheet===sheet ? 'rgba(34,197,94,0.1)' : 'transparent', border: `1px solid ${filter.sheet===sheet ? '#22c55e' : '#2a2a2a'}`, borderRadius:'6px', color: filter.sheet===sheet ? '#22c55e' : '#6b7280', fontSize:'11px', cursor:'pointer' }}
              onClick={() => setFilter({ ...filter, sheet })}
            >{sheet}</button>
          ))}
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:'6px' }}>
          <span style={{ fontSize:'11px', color:'#6b7280', marginRight:'4px' }}>Difficulty:</span>
          {['All','Easy','Medium','Hard'].map(d => (
            <button key={d}
              style={{ padding:'5px 12px', background: filter.difficulty===d ? (d==='All' ? 'rgba(34,197,94,0.1)' : `${dc[d]}15`) : 'transparent', border: `1px solid ${filter.difficulty===d ? (d==='All' ? '#22c55e' : dc[d]) : '#2a2a2a'}`, borderRadius:'6px', color: filter.difficulty===d ? (d==='All' ? '#22c55e' : dc[d]) : '#6b7280', fontSize:'11px', cursor:'pointer' }}
              onClick={() => setFilter({ ...filter, difficulty: d })}
            >{d}</button>
          ))}
        </div>
        <span style={{ fontSize:'11px', color:'#6b7280', marginLeft:'auto' }}>{filtered.length} problems</span>
      </div>

      {/* Problems List */}
      <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
        {Object.entries(grouped).map(([topic, topicProblems]) => {
          const topicSolved = topicProblems.filter(p => solved[p._id]).length;
          const isOpen = activeGroup === topic || activeGroup === null;
          return (
            <div key={topic} style={{ background:'#0a0a0a', border:'1px solid #141414', borderRadius:'14px', overflow:'hidden' }}>

              {/* Topic Header */}
              <div
                style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'14px 18px', cursor:'pointer', borderBottom:'1px solid #141414' }}
                onClick={() => setActiveGroup(activeGroup === topic ? null : topic)}
              >
                <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                  <span style={{ color:'#6b7280', fontSize:'12px' }}>{isOpen ? '▾' : '▸'}</span>
                  <span style={{ fontSize:'13px', fontWeight:'600', color:'#ffffff' }}>{topic}</span>
                  <span style={{ fontSize:'11px', color:'#4b5563' }}>{topicProblems.length} problems</span>
                </div>
                <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                  <div style={{ width:'80px', height:'3px', background:'#1a1a1a', borderRadius:'999px', overflow:'hidden' }}>
                    <div style={{ height:'100%', width:`${(topicSolved/topicProblems.length)*100}%`, background:'#22c55e', borderRadius:'999px' }}></div>
                  </div>
                  <span style={{ fontSize:'11px', color:'#6b7280' }}>{topicSolved}/{topicProblems.length}</span>
                </div>
              </div>

              {/* Problems */}
              {isOpen && (
                <div style={{ display:'flex', flexDirection:'column' }}>
                  {topicProblems.map((problem, idx) => {
                    const isSolved = solved[problem._id];
                    return (
                      <div key={problem._id} style={{ display:'flex', alignItems:'center', gap:'12px', padding:'12px 18px', borderBottom:'1px solid #0d0d0d', background: isSolved ? 'rgba(34,197,94,0.04)' : '#0f0f0f' }}>

                        <div
                          onClick={() => toggleSolved(problem)}
                          style={{ width:'18px', height:'18px', borderRadius:'5px', border:`1.5px solid ${isSolved ? '#22c55e' : '#2a2a2a'}`, background: isSolved ? '#22c55e' : 'transparent', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}
                        >
                          {isSolved && <span style={{ fontSize:'11px', color:'#000', fontWeight:'700' }}>✓</span>}
                        </div>

                        <span style={{ fontSize:'11px', color:'#374151', minWidth:'20px' }}>{idx+1}</span>

                        <span style={{ flex:1, fontSize:'13px', fontWeight:'500', color: isSolved ? '#6b7280' : '#ffffff', textDecoration: isSolved ? 'line-through' : 'none' }}>
                          {problem.title}
                        </span>

                        <span style={{ fontSize:'10px', fontWeight:'600', padding:'3px 8px', borderRadius:'6px', color: dc[problem.difficulty], background:`${dc[problem.difficulty]}12`, border:`1px solid ${dc[problem.difficulty]}25` }}>
                          {problem.difficulty}
                        </span>

                        <span style={{ fontSize:'10px', color:'#4b5563', background:'#141414', border:'1px solid #1f1f1f', padding:'3px 8px', borderRadius:'6px' }}>
                          {problem.sheet}
                        </span>

                        {problem.leetcodeUrl
                          ? <a href={problem.leetcodeUrl} target="_blank" rel="noreferrer" style={{ fontSize:'11px', color:'#3b82f6', textDecoration:'none', fontWeight:'500' }}>LC →</a>
                          : <span style={{ width:'32px' }}></span>
                        }

                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default DSATracker;
